import{_ as e,c as o,o as a,a1 as s}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"Token Stats: Cost Metrics | Antigravity-Manager","description":"Learn Token Stats metrics: extract token data from proxy responses, write to local SQLite, analyze usage by model and account across hourly/daily/weekly dimensions, locate expensive models and accounts, troubleshoot missing statistics.","frontmatter":{"title":"Token Stats: Cost Metrics | Antigravity-Manager","sidebarTitle":"Token Stats","subtitle":"Token Stats: Cost-Perspective Metrics and Chart Interpretation","description":"Learn Token Stats metrics: extract token data from proxy responses, write to local SQLite, analyze usage by model and account across hourly/daily/weekly dimensions, locate expensive models and accounts, troubleshoot missing statistics.","tags":["Token Stats","Cost","Monitoring","SQLite","Usage Statistics"],"prerequisite":["start-proxy-and-first-client","advanced-model-router"],"order":999},"headers":[],"relativePath":"lbjlaq/Antigravity-Manager/advanced/token-stats/index.md","filePath":"lbjlaq/Antigravity-Manager/advanced/token-stats/index.md"}'),r={name:"lbjlaq/Antigravity-Manager/advanced/token-stats/index.md"};function i(n,t,d,l,c,u){return a(),o("div",null,[...t[0]||(t[0]=[s('<h1 id="token-stats-cost-perspective-metrics-and-chart-interpretation" tabindex="-1">Token Stats: Cost-Perspective Metrics and Chart Interpretation <a class="header-anchor" href="#token-stats-cost-perspective-metrics-and-chart-interpretation" aria-label="Permalink to &quot;Token Stats: Cost-Perspective Metrics and Chart Interpretation&quot;">​</a></h1><p>You&#39;ve already connected your client to Antigravity Tools, but determining &quot;who&#39;s spending, what&#39;s expensive, and whether a specific model suddenly spiked&quot; is hard to judge by intuition alone. This lesson does one thing: clarify the data metrics on the Token Stats page and teach you how to use charts to quickly pinpoint cost issues.</p><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><ul><li>Explain where Token Stats data comes from (when it gets recorded, and when it&#39;s missing)</li><li>Switch between hourly/daily/weekly observation windows to avoid misjudgments caused by &quot;looking at just one day&quot;</li><li>In both &quot;By Model&quot; and &quot;By Account&quot; views, use trend charts to identify abnormal peaks</li><li>Use Top lists to lock down the most expensive models/accounts, then return to request logs to trace root causes</li></ul><h2 id="your-current-struggles" tabindex="-1">Your Current Struggles <a class="header-anchor" href="#your-current-struggles" aria-label="Permalink to &quot;Your Current Struggles&quot;">​</a></h2><ul><li>You feel calls are getting more expensive, but don&#39;t know whether it&#39;s due to model changes, account changes, or a sudden volume spike on a specific day</li><li>You see <code>X-Mapped-Model</code> but aren&#39;t sure which model standard the statistics actually use</li><li>Token Stats occasionally shows 0 or &quot;No data available&quot;—you don&#39;t know if there&#39;s no traffic or if statistics weren&#39;t captured</li></ul><h2 id="when-to-use-this-feature" tabindex="-1">When to Use This Feature <a class="header-anchor" href="#when-to-use-this-feature" aria-label="Permalink to &quot;When to Use This Feature&quot;">​</a></h2><ul><li>You&#39;re doing cost optimization: first quantify &quot;who&#39;s most expensive&quot;</li><li>You&#39;re troubleshooting sudden rate limits or anomalies: use peak time points to cross-reference request logs</li><li>After making changes to model routing or quota governance, you want to verify costs are decreasing as expected</li></ul><h2 id="what-is-token-stats" tabindex="-1">What Is Token Stats? <a class="header-anchor" href="#what-is-token-stats" aria-label="Permalink to &quot;What Is Token Stats?&quot;">​</a></h2><p><strong>Token Stats</strong> is the local usage statistics page of Antigravity Tools: after forwarding requests, the proxy attempts to extract token counts from <code>usage/usageMetadata</code> in response JSON or streaming data, writes each request to local SQLite (<code>token_stats.db</code>) by account and model, and finally displays aggregated data in the UI by time/model/account.</p><div class="info custom-block"><p class="custom-block-title">Important: one common pitfall</p><p>The &quot;model&quot; standard in Token Stats comes from the <code>model</code> field in your request (or path parsing like Gemini&#39;s <code>/v1beta/models/&lt;model&gt;</code>), not the routed <code>X-Mapped-Model</code>.</p></div><h2 id="🎒-before-you-start" tabindex="-1">🎒 Before You Start <a class="header-anchor" href="#🎒-before-you-start" aria-label="Permalink to &quot;🎒 Before You Start&quot;">​</a></h2><ul><li>You&#39;ve already successfully made at least one proxy call (not just停留在 <code>/healthz</code> health checks)</li><li>Your upstream responses return parsable token usage fields (otherwise statistics will be missing)</li></ul><div class="tip custom-block"><p class="custom-block-title">Recommended reading</p><p>If you&#39;re using model mapping to route <code>model</code> to different physical models, it&#39;s recommended to first read <strong><a href="/docs/opencodedocs/lbjlaq/Antigravity-Manager/advanced/model-router/">Model Router: Custom Mapping, Wildcard Priority, and Preset Strategies</a></strong>, then come back here—the &quot;statistical standards&quot; will be more intuitive.</p></div><h2 id="core-approach" tabindex="-1">Core Approach <a class="header-anchor" href="#core-approach" aria-label="Permalink to &quot;Core Approach&quot;">​</a></h2><p>The Token Stats data pipeline can be broken into three segments:</p><ol><li>Proxy middleware attempts to extract token usage from responses (supports <code>usage</code>/<code>usageMetadata</code>, streaming data is also parsed)</li><li>If both <code>account_email + input_tokens + output_tokens</code> are obtained, write to local SQLite (<code>token_stats.db</code>)</li><li>UI pulls aggregated data via Tauri <code>invoke(get_token_stats_*)</code>, displaying by hour/day/week</li></ol><h2 id="follow-along" tabindex="-1">Follow Along <a class="header-anchor" href="#follow-along" aria-label="Permalink to &quot;Follow Along&quot;">​</a></h2><h3 id="step-1-first-confirm-you-have-traffic" tabindex="-1">Step 1: First confirm you &quot;have traffic&quot; <a class="header-anchor" href="#step-1-first-confirm-you-have-traffic" aria-label="Permalink to &quot;Step 1: First confirm you &quot;have traffic&quot;&quot;">​</a></h3><p><strong>Why</strong> Token Stats statistics come from real requests. If you only start the proxy but never make a single model request, the page will display &quot;No data available&quot;.</p><p>How to do it: reuse the call method you already verified in <strong><a href="/docs/opencodedocs/lbjlaq/Antigravity-Manager/start/proxy-and-first-client/">Start Local Reverse Proxy and Connect Your First Client</a></strong>, send 1-2 requests.</p><p><strong>What you should see</strong>: The Token Stats page changes from &quot;Loading/No data available&quot; to displaying charts or lists.</p><h3 id="step-2-choose-the-right-time-window-hour-day-week" tabindex="-1">Step 2: Choose the right time window (hour/day/week) <a class="header-anchor" href="#step-2-choose-the-right-time-window-hour-day-week" aria-label="Permalink to &quot;Step 2: Choose the right time window (hour/day/week)&quot;">​</a></h3><p><strong>Why</strong> The same data shows completely different &quot;peaks/trends&quot; under different windows. The three windows in the UI correspond to different data ranges:</p><ul><li>Hour: last 24 hours</li><li>Day: last 7 days</li><li>Week: last 4 weeks (trend view aggregates over the last 30 days)</li></ul><p><strong>What you should see</strong>: After switching, the trend chart&#39;s x-axis granularity changes (hour shows &quot;hour&quot;, day shows &quot;month/day&quot;, week shows &quot;year-Wweek number&quot;).</p><h3 id="step-3-first-look-at-the-top-summary-to-determine-cost-scale" tabindex="-1">Step 3: First look at the top summary to determine &quot;cost scale&quot; <a class="header-anchor" href="#step-3-first-look-at-the-top-summary-to-determine-cost-scale" aria-label="Permalink to &quot;Step 3: First look at the top summary to determine &quot;cost scale&quot;&quot;">​</a></h3><p><strong>Why</strong> Summary cards first answer 3 questions: is the total volume large, is the input/output ratio abnormal, and did the number of active accounts/models suddenly increase.</p><p>Focus on these items:</p><ul><li>Total tokens (<code>total_tokens</code>)</li><li>Input/output tokens (<code>total_input_tokens</code> / <code>total_output_tokens</code>)</li><li>Active account count (<code>unique_accounts</code>)</li><li>Number of models used (UI uses the length of &quot;model-specific statistics list&quot; directly)</li></ul><p><strong>What you should see</strong>: If &quot;active account count&quot; suddenly spikes, it usually means you ran more accounts in a short time (e.g., switching to a rotation strategy).</p><h3 id="step-4-use-model-account-usage-trends-to-catch-abnormal-peaks" tabindex="-1">Step 4: Use &quot;Model/Account Usage Trends&quot; to catch abnormal peaks <a class="header-anchor" href="#step-4-use-model-account-usage-trends-to-catch-abnormal-peaks" aria-label="Permalink to &quot;Step 4: Use &quot;Model/Account Usage Trends&quot; to catch abnormal peaks&quot;">​</a></h3><p><strong>Why</strong> Trend charts are the best entry point for catching &quot;suddenly expensive&quot; issues. You don&#39;t need to know the cause first—first identify &quot;which day/hour spiked&quot;.</p><p>How to do it:</p><ol><li>In the top-right of the trend chart, switch between &quot;By Model / By Account&quot;</li><li>Hover (Tooltip) to see Top values, prioritize关注 &quot;the one that suddenly shot to first place&quot;</li></ol><p><strong>What you should see</strong>:</p><ul><li>By model: a certain model suddenly rises during a specific time period</li><li>By account: a certain account suddenly rises during a specific time period</li></ul><h3 id="step-5-use-top-lists-to-lock-down-most-expensive-targets" tabindex="-1">Step 5: Use Top lists to lock down &quot;most expensive targets&quot; <a class="header-anchor" href="#step-5-use-top-lists-to-lock-down-most-expensive-targets" aria-label="Permalink to &quot;Step 5: Use Top lists to lock down &quot;most expensive targets&quot;&quot;">​</a></h3><p><strong>Why</strong> Trend charts tell you &quot;when it&#39;s abnormal&quot;, Top lists tell you &quot;who&#39;s most expensive&quot;. Cross-reference these two to quickly narrow down troubleshooting scope.</p><p>How to do it:</p><ul><li>In &quot;By Model&quot; view, look at <code>total_tokens / request_count / percentage</code> in the &quot;Model-Specific Statistics&quot; table</li><li>In &quot;By Account&quot; view, look at <code>total_tokens / request_count</code> in the &quot;Account-Specific Statistics&quot; table</li></ul><p><strong>What you should see</strong>: The most expensive models/accounts appear at the top, and <code>request_count</code> helps you distinguish between &quot;one-time very expensive&quot; vs &quot;many times&quot;.</p><h3 id="step-6-optional-find-token-stats-db-do-backups-verification" tabindex="-1">Step 6 (Optional): Find <code>token_stats.db</code>, do backups/verification <a class="header-anchor" href="#step-6-optional-find-token-stats-db-do-backups-verification" aria-label="Permalink to &quot;Step 6 (Optional): Find `token_stats.db`, do backups/verification&quot;">​</a></h3><p><strong>Why</strong> When you suspect &quot;missing statistics&quot; or want to do offline analysis, taking the SQLite file directly is most reliable.</p><p>How to do it: go to Settings &gt; Advanced section, click &quot;Open Data Directory&quot;, and you&#39;ll find <code>token_stats.db</code> in the data directory.</p><p><strong>What you should see</strong>: The file list contains <code>token_stats.db</code> (filename is hardcoded by the backend).</p><h2 id="checkpoint-✅" tabindex="-1">Checkpoint ✅ <a class="header-anchor" href="#checkpoint-✅" aria-label="Permalink to &quot;Checkpoint ✅&quot;">​</a></h2><ul><li>You can clearly explain that Token Stats statistics are &quot;extracted from response usage/usageMetadata and written to local SQLite&quot;, not cloud billing</li><li>In both &quot;By Model&quot; and &quot;By Account&quot; trend views, you can identify a specific peak time period</li><li>You can provide an actionable troubleshooting conclusion using Top lists: which model or account to check first</li></ul><h2 id="common-pitfalls" tabindex="-1">Common Pitfalls <a class="header-anchor" href="#common-pitfalls" aria-label="Permalink to &quot;Common Pitfalls&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Phenomenon</th><th>Common Cause</th><th>What You Can Do</th></tr></thead><tbody><tr><td>Token Stats shows &quot;No data available&quot;</td><td>You indeed haven&#39;t generated model requests; or upstream responses don&#39;t contain parsable token fields</td><td>First use an already verified client to send requests; then check if responses include <code>usage/usageMetadata</code></td></tr><tr><td>Statistics by &quot;model&quot; look wrong</td><td>Statistics use the <code>model</code> from requests, not <code>X-Mapped-Model</code></td><td>Treat model routing as &quot;request model -&gt; mapped model&quot;; statistics view the &quot;request model&quot;</td></tr><tr><td>Account dimension missing</td><td>Only writes when <code>X-Account-Email</code> is obtained AND token usage is parsed</td><td>Confirm requests actually go through the account pool; then cross-reference request logs/response headers</td></tr></tbody></table><h2 id="lesson-summary" tabindex="-1">Lesson Summary <a class="header-anchor" href="#lesson-summary" aria-label="Permalink to &quot;Lesson Summary&quot;">​</a></h2><ul><li>Token Stats&#39; core value is &quot;quantifying cost issues&quot;—first locate, then optimize</li><li>Statistical writing depends on three elements: account, model, token usage (missing any one means no write)</li><li>For more refined cost control, the next step is usually to return to model routing or quota governance</li></ul><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Last updated: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Function</th><th>File Path</th><th>Line Numbers</th></tr></thead><tbody><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Token Stats UI: time window/view switching and data fetching</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/TokenStats.tsx#L49-L166" target="_blank" rel="noreferrer"><code>src/pages/TokenStats.tsx</code></a></td><td>49-166</td></tr><tr><td>Token Stats UI: empty data prompt (&quot;No data available&quot;)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/TokenStats.tsx#L458-L507" target="_blank" rel="noreferrer"><code>src/pages/TokenStats.tsx</code></a></td><td>458-507</td></tr><tr><td>Token usage extraction: parse model from request, parse usage/usageMetadata from response</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/middleware/monitor.rs#L32-L120" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/middleware/monitor.rs</code></a></td><td>32-120</td></tr><tr><td>Token usage extraction: parse usage field from streaming and JSON responses</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/middleware/monitor.rs#L122-L336" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/middleware/monitor.rs</code></a></td><td>122-336</td></tr><tr><td>Token Stats write point: write to SQLite after obtaining account+tokens</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/monitor.rs#L79-L136" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/monitor.rs</code></a></td><td>79-136</td></tr><tr><td>Database filename and table structure: <code>token_stats.db</code> / <code>token_usage</code> / <code>token_stats_hourly</code></td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/token_stats.rs#L58-L126" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/token_stats.rs</code></a></td><td>58-126</td></tr><tr><td>Write logic: <code>record_usage(account_email, model, input, output)</code></td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/token_stats.rs#L128-L159" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/token_stats.rs</code></a></td><td>128-159</td></tr><tr><td>Query logic: hour/day/week, by account/by model, trends and summary</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/token_stats.rs#L161-L555" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/token_stats.rs</code></a></td><td>161-555</td></tr><tr><td>Tauri commands: <code>get_token_stats_*</code> exposed to frontend</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L791-L847" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>791-847</td></tr><tr><td>Initialize Token Stats DB on app startup</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/lib.rs#L50-L56" target="_blank" rel="noreferrer"><code>src-tauri/src/lib.rs</code></a></td><td>50-56</td></tr><tr><td>Settings page: get/open data directory (to find <code>token_stats.db</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L76-L143" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>76-143</td></tr></tbody></table></details>',55)])])}const m=e(r,[["render",i]]);export{p as __pageData,m as default};
